  "trigger_method": [
    "org.jsoup.helper.DataUtilTest::testCharset",
    "org.jsoup.helper.DataUtilTest::testQuotedCharset"
  ],
  "fixed_code": [
    "static String getCharsetFromContentType(String contentType) {
        if (contentType == null) return null;
        Matcher m = charsetPattern.matcher(contentType);
        if (m.find()) {
            String charset = m.group(1).trim();
            // remove optional surrounding quotes
            if ((charset.startsWith("\"") && charset.endsWith("\"")) || (charset.startsWith("'") && charset.endsWith("'"))) {
                charset = charset.substring(1, charset.length() - 1).trim();
            }
            try {
                if (Charset.isSupported(charset))
                    return charset; // preserve original case
            } catch (IllegalCharsetNameException e) {
                // fall through to return null
            }
        }
        return null;
    }"
  ]
}

{
  "trigger_method": [
    "org.jsoup.safety.CleanerTest::testIsValid"
  ],
  "fixed_code": [
    "private int copySafeNodes(Element root, Element destination) {
        List<Node> sourceChildren = root.childNodes();
        int numDiscarded = 0;

        for (Node source : sourceChildren) {
            if (source instanceof Element) {
                Element sourceEl = (Element) source;

                if (whitelist.isSafeTag(sourceEl.tagName())) { // safe, clone and copy safe attrs
                    ElementMeta meta = createSafeElement(sourceEl);
                    Element destChild = meta.el;
                    destination.appendChild(destChild);

                    numDiscarded += meta.numAttribsDiscarded;
                    numDiscarded += copySafeNodes(sourceEl, destChild);
                } else {
                    numDiscarded++;
                    numDiscarded += copySafeNodes(sourceEl, destination);
                }
            } else if (source instanceof TextNode) {
                TextNode sourceText = (TextNode) source;
                TextNode destText = new TextNode(sourceText.getWholeText(), source.baseUri());
                destination.appendChild(destText);
            } else {
                // discard other node types (e.g., comments, xml declarations, data nodes) and count as discarded
                numDiscarded++;
            }
        }
        return numDiscarded;


    }"
  ]
}

